import { beforeAll, afterAll, describe, expect, it } from 'vitest';
import { pool } from './client.js';
import { seed } from './seed.js';

const REQUIRED_TABLES = [
  'workspaces',
  'users',
  'workspace_memberships',
  'documents',
  'document_associations',
  'document_history',
  'document_snapshots',
  'api_tokens',
  'sessions',
];

const REQUIRED_DOCUMENT_COLUMNS = [
  'workspace_id',
  'document_type',
  'title',
  'content',
  'yjs_state',
  'parent_id',
  'position',
  'properties',
  'ticket_number',
  'archived_at',
  'deleted_at',
  'started_at',
  'completed_at',
  'cancelled_at',
  'reopened_at',
  'converted_to_id',
  'converted_from_id',
  'converted_at',
  'converted_by',
  'original_type',
  'conversion_count',
  'created_at',
  'updated_at',
  'created_by',
  'visibility',
];

describe('database migration and seed verification', () => {
  const runId = `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
  const seededWorkspaceName = 'Ship Workspace';
  let seededWorkspaceId: string | null = null;

  beforeAll(async () => {
    await seed();
    const workspace = await pool.query(
      'SELECT id FROM workspaces WHERE name = $1 ORDER BY created_at DESC LIMIT 1',
      [seededWorkspaceName],
    );
    seededWorkspaceId = workspace.rows[0]?.id ?? null;
  });

  afterAll(async () => {
    await pool.query(`DELETE FROM documents WHERE workspace_id = $1`, [seededWorkspaceId]);
    await pool.query(`DELETE FROM workspace_memberships WHERE workspace_id = $1`, [seededWorkspaceId]);
    await pool.query(`DELETE FROM users WHERE email = 'dev@ship.local'`);
    await pool.query(`DELETE FROM workspaces WHERE id = $1`, [seededWorkspaceId]);
  });

  it('creates the required core tables and document columns', async () => {
    for (const tableName of REQUIRED_TABLES) {
      const result = await pool.query(
        `SELECT to_regclass($1) AS regclass`,
        [tableName],
      );
      expect(result.rows[0]?.regclass).toBe(tableName);
    }

    const columns = await pool.query(
      `SELECT column_name
       FROM information_schema.columns
       WHERE table_schema = 'public' AND table_name = 'documents'`,
    );
    const columnSet = new Set(columns.rows.map((row) => row.column_name as string));

    for (const column of REQUIRED_DOCUMENT_COLUMNS) {
      expect(columnSet.has(column)).toBe(true);
    }
  });

  it('seeds the demo workspace, admin user, and sample documents', async () => {
    expect(seededWorkspaceId).toBeTruthy();

    const workspace = await pool.query(
      'SELECT name FROM workspaces WHERE id = $1',
      [seededWorkspaceId],
    );
    expect(workspace.rows[0]?.name).toBe(seededWorkspaceName);

    const adminUser = await pool.query(
      `SELECT u.email, u.is_super_admin, wm.role
       FROM users u
       JOIN workspace_memberships wm ON wm.user_id = u.id
       WHERE u.email = 'dev@ship.local' AND wm.workspace_id = $1`,
      [seededWorkspaceId],
    );
    expect(adminUser.rows[0]?.email).toBe('dev@ship.local');
    expect(adminUser.rows[0]?.is_super_admin).toBe(true);
    expect(adminUser.rows[0]?.role).toBe('admin');

    const seededDocuments = await pool.query(
      `SELECT document_type, title, properties
       FROM documents
       WHERE workspace_id = $1
         AND (document_type IN ('program', 'project', 'issue', 'person') OR title LIKE 'Week %')`,
      [seededWorkspaceId],
    );

    expect(seededDocuments.rows.length).toBeGreaterThan(0);
    expect(seededDocuments.rows.some((row) => row.document_type === 'program')).toBe(true);
    expect(seededDocuments.rows.some((row) => row.document_type === 'project')).toBe(true);
    expect(seededDocuments.rows.some((row) => row.document_type === 'issue')).toBe(true);
    expect(seededDocuments.rows.some((row) => row.document_type === 'person')).toBe(true);
    expect(seededDocuments.rows.some((row) => String(row.title).startsWith('Week '))).toBe(true);
  });
});

