import pg from 'pg';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import { loadEnvFiles } from '../config/env.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

loadEnvFiles(join(__dirname, '../..'));

const { Pool } = pg;

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  max: Number(process.env.PGPOOL_MAX ?? 10),
  idleTimeoutMillis: Number(process.env.PGPOOL_IDLE_TIMEOUT_MS ?? 30000),
  connectionTimeoutMillis: Number(process.env.PGPOOL_CONNECTION_TIMEOUT_MS ?? 2000),
  statement_timeout: Number(process.env.PGPOOL_STATEMENT_TIMEOUT_MS ?? 30000),
});

let isShuttingDown = false;

async function shutdown(signal: 'SIGTERM' | 'SIGINT') {
  if (isShuttingDown) return;
  isShuttingDown = true;

  try {
    console.info(`${signal} received, closing database pool...`);
    await pool.end();
    console.info('Database pool closed');
  } catch (error) {
    console.error('Failed to close database pool cleanly:', error);
    process.exitCode = 1;
  } finally {
    process.exit(process.exitCode ?? 0);
  }
}

process.once('SIGTERM', () => {
  void shutdown('SIGTERM');
});

process.once('SIGINT', () => {
  void shutdown('SIGINT');
});

export { pool };

