import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import crypto from 'crypto';
import pg from 'pg';
import bcrypt from 'bcryptjs';
import { loadProductionSecrets } from '../config/ssm.js';
import { loadEnvFiles } from '../config/env.js';
import { ensureDatabaseSchema } from './bootstrap.js';
import { WELCOME_DOCUMENT_TITLE, WELCOME_DOCUMENT_CONTENT } from './welcomeDocument.js';
import { getDatabaseSslConfig } from './ssl.js';

import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import crypto from 'crypto';
import pg from 'pg';
import bcrypt from 'bcryptjs';
import { loadProductionSecrets } from '../config/ssm.js';
import { loadEnvFiles } from '../config/env.js';
import { ensureDatabaseSchema } from './bootstrap.js';
import { WELCOME_DOCUMENT_TITLE, WELCOME_DOCUMENT_CONTENT } from './welcomeDocument.js';
import { getDatabaseSslConfig } from './ssl.js';

const { Pool } = pg;

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

loadEnvFiles(join(__dirname, '../..'));

async function seed() {
  await loadProductionSecrets();

  const pool = new Pool({
    connectionString: process.env.DATABASE_URL,
    ssl: getDatabaseSslConfig(),
  });

  console.log('🌱 Starting database seed...');

  try {
    await ensureDatabaseSchema(pool, console);

    const workspaceName = 'Ship Demo Workspace';
    const adminEmail = 'admin@ship.local';
    const adminPassword = 'admin123';
    const passwordHash = await bcrypt.hash(adminPassword, 10);

    const workspaceResult = await pool.query(
      `INSERT INTO workspaces (name, sprint_start_date)
       VALUES ($1, CURRENT_DATE)
       ON CONFLICT DO NOTHING
       RETURNING id`,
      [workspaceName]
    );

    let workspaceId = workspaceResult.rows[0]?.id as string | undefined;
    if (!workspaceId) {
      const existingWorkspace = await pool.query('SELECT id FROM workspaces WHERE name = $1 LIMIT 1', [workspaceName]);
      workspaceId = existingWorkspace.rows[0]?.id;
    }

    if (!workspaceId) {
      throw new Error('Failed to create or find demo workspace');
    }

    const adminUserResult = await pool.query(
      `INSERT INTO users (email, password_hash, name, is_super_admin, last_workspace_id)
       VALUES ($1, $2, $3, TRUE, $4)
       ON CONFLICT (email) DO UPDATE
       SET password_hash = EXCLUDED.password_hash,
           name = EXCLUDED.name,
           is_super_admin = TRUE,
           last_workspace_id = EXCLUDED.last_workspace_id,
           updated_at = NOW()
       RETURNING id`,
      [adminEmail, passwordHash, 'Admin User', workspaceId]
    );

    const adminUserId = adminUserResult.rows[0].id as string;

    await pool.query(
      `INSERT INTO workspace_memberships (workspace_id, user_id, role)
       VALUES ($1, $2, 'admin')
       ON CONFLICT (workspace_id, user_id) DO UPDATE
       SET role = 'admin',
           updated_at = NOW()`,
      [workspaceId, adminUserId]
    );

    const docs = {
      welcome: {
        title: WELCOME_DOCUMENT_TITLE,
        type: 'wiki',
        content: WELCOME_DOCUMENT_CONTENT,
        properties: { category: 'overview', featured: true },
      },
      handbook: {
        title: 'Team Handbook',
        type: 'wiki',
        content: {
          type: 'doc',
          content: [
            { type: 'heading', attrs: { level: 1 }, content: [{ type: 'text', text: 'Team Handbook' }] },
            { type: 'paragraph', content: [{ type: 'text', text: 'Guidelines, expectations, and team norms for the demo workspace.' }] },
          ],
        },
        properties: { category: 'documentation' },
      },
      program: {
        title: 'Ship Core',
        type: 'program',
        content: {
          type: 'doc',
          content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Core product initiatives and roadmap.' }] }],
        },
        properties: { prefix: 'SHIP', color: '#3B82F6' },
      },
      project: {
        title: 'Ship Core - Demo Project',
        type: 'project',
        content: {
          type: 'doc',
          content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Representative project with planning metadata.' }] }],
        },
        properties: { owner_id: adminUserId, color: '#6366f1', emoji: '🚀', impact: 5, confidence: 4, ease: 3 },
      },
      sprint: {
        title: 'Week 1',
        type: 'sprint',
        content: {
          type: 'doc',
          content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Current sprint planning and execution.' }] }],
        },
        properties: { sprint_number: 1, owner_id: adminUserId, status: 'active', confidence: 78 },
      },
      issueTodo: {
        title: 'Set up demo environment',
        type: 'issue',
        content: {
          type: 'doc',
          content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Prepare the local demo environment and sample data.' }] }],
        },
        properties: { state: 'todo', priority: 'high', assignee_id: adminUserId, source: 'internal', estimate: 4 },
      },
      issueProgress: {
        title: 'Build sample dashboard',
        type: 'issue',
        content: {
          type: 'doc',
          content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Create a representative dashboard for stakeholders.' }] }],
        },
        properties: { state: 'in_progress', priority: 'medium', assignee_id: adminUserId, source: 'internal', estimate: 8 },
      },
      person: {
        title: 'Admin User',
        type: 'person',
        content: {
          type: 'doc',
          content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Administrator account seeded for demo access.' }] }],
        },
        properties: { user_id: adminUserId, email: adminEmail, capacity_hours: 40, skills: ['management', 'full-stack'] },
      },
    } as const;

    const existingDocs = await pool.query('SELECT title, document_type FROM documents WHERE workspace_id = $1', [workspaceId]);
    const existingKeySet = new Set(existingDocs.rows.map((row: { title: string; document_type: string }) => `${row.document_type}:${row.title}`));

    const insertDoc = async (key: keyof typeof docs, extra?: { parentId?: string }) => {
      const doc = docs[key];
      const docKey = `${doc.type}:${doc.title}`;
      if (existingKeySet.has(docKey)) return;
      const result = await pool.query(
        `INSERT INTO documents (workspace_id, document_type, title, content, properties, created_by, parent_id)
         VALUES ($1, $2, $3, $4, $5, $6, $7)
         RETURNING id`,
        [workspaceId, doc.type, doc.title, JSON.stringify(doc.content), JSON.stringify(doc.properties), adminUserId, extra?.parentId ?? null]
      );
      existingKeySet.add(docKey);
      return result.rows[0].id as string;
    };

    const welcomeId = await insertDoc('welcome');
    const handbookId = await insertDoc('handbook', { parentId: welcomeId });
    const programId = await insertDoc('program');
    const projectId = await insertDoc('project');
    const sprintId = await insertDoc('sprint');
    const issueTodoId = await insertDoc('issueTodo');
    const issueProgressId = await insertDoc('issueProgress');
    const personId = await insertDoc('person');

    const associations = [
      [projectId, programId, 'program'],
      [sprintId, projectId, 'project'],
      [sprintId, programId, 'program'],
      [issueTodoId, programId, 'program'],
      [issueTodoId, projectId, 'project'],
      [issueTodoId, sprintId, 'sprint'],
      [issueProgressId, programId, 'program'],
      [issueProgressId, projectId, 'project'],
      [issueProgressId, sprintId, 'sprint'],
    ].filter(([a, b]) => Boolean(a && b)) as Array<[string, string, 'program' | 'project' | 'sprint']>;

    for (const [documentId, relatedId, relationshipType] of associations) {
      await pool.query(
        `INSERT INTO document_associations (document_id, related_id, relationship_type, metadata)
         VALUES ($1, $2, $3, $4)
         ON CONFLICT (document_id, related_id, relationship_type) DO NOTHING`,
        [documentId, relatedId, relationshipType, JSON.stringify({ seeded: true })]
      );
    }

    await pool.query(
      `INSERT INTO document_links (source_id, target_id)
       VALUES ($1, $2)
       ON CONFLICT DO NOTHING`,
      [welcomeId, handbookId]
    );

    if (personId) {
      await pool.query(
        `INSERT INTO comments (document_id, comment_id, author_id, workspace_id, content)
         VALUES ($1, $2, $3, $4, $5)
         ON CONFLICT DO NOTHING`,
        [welcomeId, crypto.randomUUID(), adminUserId, workspaceId, 'Welcome to the demo workspace!']
      );
    }

    console.log(`✅ Seeded workspace "${workspaceName}" with admin ${adminEmail}`);
    console.log(`🔑 Demo password: ${adminPassword}`);
  } finally {
    await pool.end();
  }
}

seed().catch((error) => {
  console.error('❌ Database seed failed:', error);
  process.exitCode = 1;
});

