    68	  const appliedNow: string[] = [];
    69	
    70	  for (const file of migrationFiles) {
    71	    const version = file.replace(/\.sql$/, '');
    72	    if (appliedMigrations.has(version)) {
    73	      continue;
    74	    }
    75	
    76	    const client = await pool.connect();
    77	    try {
    78	      await client.query('BEGIN');
    79	      await client.query(readFileSync(join(migrationsDir, file), 'utf-8'));
    80	      await client.query('INSERT INTO schema_migrations (version) VALUES ($1)', [version]);
    81	      await client.query('COMMIT');
    82	      appliedNow.push(version);
    83	      logger?.log(`Applied migration ${version}`);
    84	    } catch (error) {
    85	      await client.query('ROLLBACK');
    86	      logger?.error(`Migration failed: ${version}`);
    87	      throw error;
    88	    } finally {
    89	      client.release();
    90	    }
    91	  }
