import { beforeAll, afterAll, describe, expect, it } from 'vitest';
import { pool } from './client.js';
import { seed } from './seed.js';

const REQUIRED_TABLES = [
  'workspaces',
  'users',
  'workspace_memberships',
  'documents',
  'document_associations',
  'document_history',
  'document_snapshots',
  'api_tokens',
  'sessions',
];

const REQUIRED_DOCUMENT_COLUMNS = [
  'workspace_id',
  'document_type',
  'title',
  'content',
  'yjs_state',
  'parent_id',
  'position',
  'properties',
  'ticket_number',
  'archived_at',
  'deleted_at',
  'started_at',
  'completed_at',
  'cancelled_at',
  'reopened_at',
  'converted_to_id',
  'converted_from_id',
  'converted_at',
  'converted_by',
  'original_type',
  'conversion_count',
  'created_at',
  'updated_at',
  'created_by',
  'visibility',
];

describe('database migration and seed verification', () => {
