    await pool.query(`DELETE FROM users WHERE email = 'dev@ship.local'`);
    await pool.query(`DELETE FROM workspaces WHERE id = $1`, [seededWorkspaceId]);
  });

  it('creates the required core tables and document columns', async () => {
    for (const tableName of REQUIRED_TABLES) {
      const result = await pool.query('SELECT to_regclass($1) AS regclass', [tableName]);
