    const workspace = await pool.query('SELECT name FROM workspaces WHERE id = $1', [seededWorkspaceId]);
    expect(workspace.rows[0]?.name).toBe(seededWorkspaceName);

    const adminUser = await pool.query(
      `SELECT u.email, u.is_super_admin, wm.role
       FROM users u
       JOIN workspace_memberships wm ON wm.user_id = u.id
       WHERE u.email = 'dev@ship.local' AND wm.workspace_id = $1`,
      [seededWorkspaceId],
    );
    expect(adminUser.rows[0]?.email).toBe('dev@ship.local');
    expect(adminUser.rows[0]?.is_super_admin).toBe(true);
    expect(adminUser.rows[0]?.role).toBe('admin');

    const seededDocuments = await pool.query(
      `SELECT document_type, title, properties
       FROM documents
       WHERE workspace_id = $1
         AND (document_type IN ('program', 'project', 'issue', 'person') OR title LIKE 'Week %')`,
      [seededWorkspaceId],
    );

    expect(seededDocuments.rows.length).toBeGreaterThan(0);
    expect(seededDocuments.rows.some((row) => row.document_type === 'program')).toBe(true);
    expect(seededDocuments.rows.some((row) => row.document_type === 'project')).toBe(true);
    expect(seededDocuments.rows.some((row) => row.document_type === 'issue')).toBe(true);
    expect(seededDocuments.rows.some((row) => row.document_type === 'person')).toBe(true);
    expect(seededDocuments.rows.some((row) => String(row.title).startsWith('Week '))).toBe(true);
  });
});

