     2	const createSchemaMigrationsTableSql = `
     3	  CREATE TABLE IF NOT EXISTS schema_migrations (
     4	    version TEXT PRIMARY KEY,
     5	    applied_at TIMESTAMPTZ DEFAULT now()
     6	  )
     7	`;
     8	
     9	type BootstrapLogger = Pick<Console, 'log' | 'error'>;
    10	type MigrationPool = Pick<pg.Pool, 'query' | 'connect'>;
    11	
    12	async function hasExistingSchema(pool: Pick<pg.Pool, 'query'>): Promise<boolean> {
    13	  const result = await pool.query(
    14	    `SELECT to_regclass('public.workspaces') IS NOT NULL AS has_schema`,
    15	  );
    16	  return result.rows[0]?.has_schema === true;
    17	}
    18	
    19	function isIgnorableSchemaError(error: unknown): boolean {
    20	  if (!(error instanceof Error) || !('code' in error)) {
    21	    return false;
    22	  }
    23	
    24	  if (error.code === '23505') {
    25	    const detail = 'detail' in error && typeof error.detail === 'string' ? error.detail : '';
    26	    return detail.includes('(extname)=(pg_trgm)');
    27	  }
    28	
    29	  return error.message.includes('already exists');
    30	}
    31	
    32	export async function ensureDatabaseSchema(
    33	  pool: MigrationPool,
    34	  logger?: BootstrapLogger,
    35	): Promise<string[]> {
    36	  if (!(await hasExistingSchema(pool))) {
    37	    const schema = readFileSync(schemaPath, 'utf-8');
    38	
    39	    try {
    40	      await pool.query(schema);
    41	    } catch (error) {
    42	      if (!isIgnorableSchemaError(error)) {
    43	        throw error;
    44	      }
    45	      logger?.log('Schema already present, continuing with pending migrations');
    46	    }
    47	  } else {
    48	    logger?.log('Existing schema detected, skipping full schema.sql replay');
    49	  }
    50	
    51	  await pool.query(createSchemaMigrationsTableSql);
    52	
    53	  const appliedResult = await pool.query('SELECT version FROM schema_migrations ORDER BY version');
    54	  const appliedMigrations = new Set(appliedResult.rows.map((row) => row.version as string));
    55	  const migrationFiles = existsSync(migrationsDir)
    56	    ? readdirSync(migrationsDir).filter((file) => file.endsWith('.sql')).sort()
    57	    : [];
    58	
    59	  const appliedNow: string[] = [];
    60	
    61	  for (const file of migrationFiles) {
    62	    const version = file.replace(/\.sql$/, '');
    63	    if (appliedMigrations.has(version)) {
    64	      continue;
    65	    }
    66	
    67	    const client = await pool.connect();
    68	    try {
    69	      await client.query('BEGIN');
    70	      await client.query(readFileSync(join(migrationsDir, file), 'utf-8'));
    71	      await client.query('INSERT INTO schema_migrations (version) VALUES ($1)', [version]);
    72	      await client.query('COMMIT');
    73	      appliedNow.push(version);
    74	      logger?.log(`Applied migration ${version}`);
    75	    } catch (error) {
    76	      await client.query('ROLLBACK');
    77	      logger?.error(`Migration failed: ${version}`);
    78	      throw error;
    79	    } finally {
    80	      client.release();
    81	    }
    82	  }
    83	
    84	  return appliedNow;
    85	}
