import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import crypto from 'crypto';
import pg from 'pg';
import bcrypt from 'bcryptjs';
import { loadEnvFiles } from '../src/config/env.js';
import { ensureDatabaseSchema } from '../src/db/bootstrap.js';
import { WELCOME_DOCUMENT_TITLE, WELCOME_DOCUMENT_CONTENT } from '../src/db/welcomeDocument.js';
import { getDatabaseSslConfig } from '../src/db/ssl.js';

const { Pool } = pg;
const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

loadEnvFiles(join(__dirname, '../..'));

async function seed() {
  const pool = new Pool({
    connectionString: process.env.DATABASE_URL,
    ssl: getDatabaseSslConfig(),
  });

  console.log('🌱 Starting database seed...');

  try {
    await ensureDatabaseSchema(pool, console);

    const workspaceName = 'Ship Demo Workspace';
    const adminEmail = 'admin@ship.local';
    const adminPassword = 'admin123';
    const passwordHash = await bcrypt.hash(adminPassword, 10);

    const workspaceResult = await pool.query(
      `INSERT INTO workspaces (name, sprint_start_date)
       VALUES ($1, CURRENT_DATE)
       ON CONFLICT DO NOTHING
       RETURNING id`,
      [workspaceName]
    );

    let workspaceId = workspaceResult.rows[0]?.id as string | undefined;
    if (!workspaceId) {
      const existingWorkspace = await pool.query('SELECT id FROM workspaces WHERE name = $1 LIMIT 1', [workspaceName]);
      workspaceId = existingWorkspace.rows[0]?.id;
    }
    if (!workspaceId) throw new Error('Failed to create or find demo workspace');

    const adminUserResult = await pool.query(
      `INSERT INTO users (email, password_hash, name, is_super_admin, last_workspace_id)
       VALUES ($1, $2, $3, TRUE, $4)
       ON CONFLICT (email) DO UPDATE
       SET password_hash = EXCLUDED.password_hash,
           name = EXCLUDED.name,
           is_super_admin = TRUE,
           last_workspace_id = EXCLUDED.last_workspace_id,
           updated_at = NOW()
       RETURNING id`,
      [adminEmail, passwordHash, 'Admin User', workspaceId]
    );
    const adminUserId = adminUserResult.rows[0].id as string;

    await pool.query(
      `INSERT INTO workspace_memberships (workspace_id, user_id, role)
       VALUES ($1, $2, 'admin')
       ON CONFLICT (workspace_id, user_id) DO UPDATE SET role = 'admin', updated_at = NOW()`,
      [workspaceId, adminUserId]
    );

    const docs = [
      {
        type: 'wiki',
        title: WELCOME_DOCUMENT_TITLE,
        content: WELCOME_DOCUMENT_CONTENT,
        properties: { category: 'overview', featured: true },
      },
      {
        type: 'wiki',
        title: 'Team Handbook',
        content: { type: 'doc', content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Guidelines for the demo workspace.' }] }] },
        properties: { category: 'documentation' },
      },
      { type: 'program', title: 'Ship Core', content: { type: 'doc', content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Core product initiatives.' }] }] }, properties: { prefix: 'SHIP', color: '#3B82F6' } },
      { type: 'project', title: 'Ship Core - Demo Project', content: { type: 'doc', content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Representative project.' }] }] }, properties: { owner_id: adminUserId, color: '#6366f1', emoji: '🚀', impact: 5, confidence: 4, ease: 3 } },
      { type: 'sprint', title: 'Week 1', content: { type: 'doc', content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Current sprint planning.' }] }] }, properties: { sprint_number: 1, owner_id: adminUserId, status: 'active', confidence: 78 } },
      { type: 'issue', title: 'Set up demo environment', content: { type: 'doc', content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Prepare demo environment and sample data.' }] }] }, properties: { state: 'todo', priority: 'high', assignee_id: adminUserId, source: 'internal', estimate: 4 } },
      { type: 'issue', title: 'Build sample dashboard', content: { type: 'doc', content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Create a representative dashboard.' }] }] }, properties: { state: 'in_progress', priority: 'medium', assignee_id: adminUserId, source: 'internal', estimate: 8 } },
      { type: 'person', title: 'Admin User', content: { type: 'doc', content: [{ type: 'paragraph', content: [{ type: 'text', text: 'Administrator account for demo access.' }] }] }, properties: { user_id: adminUserId, email: adminEmail, capacity_hours: 40, skills: ['management', 'full-stack'] } },
    ] as const;

    const ids: Record<string, string> = {};
    for (const doc of docs) {
      const existing = await pool.query(
        'SELECT id FROM documents WHERE workspace_id = $1 AND document_type = $2 AND title = $3 LIMIT 1',
        [workspaceId, doc.type, doc.title]
      );
      if (existing.rows[0]) {
        ids[doc.title] = existing.rows[0].id;
        continue;
      }
      const inserted = await pool.query(
        `INSERT INTO documents (workspace_id, document_type, title, content, properties, created_by)
         VALUES ($1, $2, $3, $4, $5, $6)
         RETURNING id`,
        [workspaceId, doc.type, doc.title, JSON.stringify(doc.content), JSON.stringify(doc.properties), adminUserId]
      );
      ids[doc.title] = inserted.rows[0].id;
    }

    const programId = ids['Ship Core'];
    const projectId = ids['Ship Core - Demo Project'];
    const sprintId = ids['Week 1'];
    const issueIds = [ids['Set up demo environment'], ids['Build sample dashboard']].filter(Boolean);

    const associations: Array<[string, string, 'program' | 'project' | 'sprint']> = [
      [projectId, programId, 'program'],
      [sprintId, projectId, 'project'],
      [sprintId, programId, 'program'],
      ...issueIds.flatMap((issueId) => [[issueId, programId, 'program'], [issueId, projectId, 'project'], [issueId, sprintId, 'sprint']] as Array<[string, string, 'program' | 'project' | 'sprint']>),
    ].filter(([a, b]) => Boolean(a && b));

    for (const [documentId, relatedId, relationshipType] of associations) {
      await pool.query(
        `INSERT INTO document_associations (document_id, related_id, relationship_type, metadata)
         VALUES ($1, $2, $3, $4)
         ON CONFLICT (document_id, related_id, relationship_type) DO NOTHING`,
        [documentId, relatedId, relationshipType, JSON.stringify({ seeded: true })]
      );
    }

    await pool.query(
      `INSERT INTO document_links (source_id, target_id)
       VALUES ($1, $2)
       ON CONFLICT DO NOTHING`,
      [ids[WELCOME_DOCUMENT_TITLE], ids['Team Handbook']]
    );

    await pool.query(
      `INSERT INTO comments (document_id, comment_id, author_id, workspace_id, content)
       VALUES ($1, $2, $3, $4, $5)`,
      [ids[WELCOME_DOCUMENT_TITLE], crypto.randomUUID(), adminUserId, workspaceId, 'Welcome to the demo workspace!']
    );

    console.log(`✅ Seeded workspace "${workspaceName}" with admin ${adminEmail}`);
    console.log(`🔑 Demo password: ${adminPassword}`);
  } finally {
    await pool.end();
  }
}

seed().catch((error) => {
  console.error('❌ Database seed failed:', error);
  process.exitCode = 1;
});

